import base64

# Helper function to recursively build the SVG markup
def convert_node(node, indent_level=1):
	indent = "  " * indent_level
	tag_name = node.get("type", "g")
	attributes = []
	children_str = ""

	# Map Ignition keys to standard SVG attributes
	attr_mapping = {
		"id": "id", "d": "d", "transform": "transform",
		"gradientTransform": "gradientTransform", "gradientUnits": "gradientUnits",
		"x1": "x1", "y1": "y1", "x2": "x2", "y2": "y2",
		"cx": "cx", "cy": "cy", "r": "r", "rx": "rx",
		"x": "x", "y": "y", "width": "width", "height": "height",
		"offset": "offset", "stopColor": "stop-color", "stopOpacity": "stop-opacity"
	}

	# Extract primary attributes
	for json_key, svg_attr in attr_mapping.items():
		if json_key in node:
			attributes.append('{}="{}"'.format(svg_attr, node[json_key]))

	# Flatten the 'fill' dictionary 
	if "fill" in node:
		fill = node["fill"]
		if "url" in fill:
			attributes.append('fill="{}"'.format(fill["url"]))
		elif "paint" in fill:
			attributes.append('fill="{}"'.format(fill["paint"]))
		if "rule" in fill:
			attributes.append('fill-rule="{}"'.format(fill["rule"]))

	# Flatten the 'stroke' dictionary
	if "stroke" in node:
		stroke = node["stroke"]
		if "paint" in stroke:
			attributes.append('stroke="{}"'.format(stroke["paint"]))
		if "width" in stroke:
			attributes.append('stroke-width="{}"'.format(stroke["width"]))
		if "linejoin" in stroke:
			attributes.append('stroke-linejoin="{}"'.format(stroke["linejoin"]))

	# Handle 'style' classes
	if "style" in node and "classes" in node["style"]:
		if node["style"]["classes"]:
			attributes.append('class="{}"'.format(node["style"]["classes"]))

	# Recursively process child elements
	if "elements" in node:
		for child in node["elements"]:
			children_str += convert_node(child, indent_level + 1)

	attr_string = " " + " ".join(attributes) if attributes else ""

	# Construct the final XML tag
	if children_str:
		return "{indent}<{tag}{attrs}>\n{children}{indent}</{tag}>\n".format(
			indent=indent, tag=tag_name, attrs=attr_string, children=children_str
		)
	else:
		return "{indent}<{tag}{attrs}/>\n".format(
			indent=indent, tag=tag_name, attrs=attr_string
		)

