svg_list = []
b64_list = []

# Guard against null or empty incoming values
if not value:
	return {"svg_list": svg_list, "b64_list": b64_list}

# Iterate through the incoming list from the binding
for icon in value:
	viewBox = icon.get("viewBox", "0 0 24 24")
	aspect = icon.get("preserveAspectRatio", "xMidYMid")

	# Start SVG container
	svg_output = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="{}" preserveAspectRatio="{}">\n'.format(viewBox, aspect)

	# Process elements
	for element in icon.get("elements", []):
		svg_output += convert_node(element)

	svg_output += '</svg>'

	# Convert to Base64 (Jython 2.7 compatible encoding)
	b64_bytes = base64.b64encode(svg_output.encode('utf-8'))
	data_uri = "data:image/svg+xml;base64," + b64_bytes.decode('utf-8')

	# Append to respective lists
	svg_list.append(svg_output)
	b64_list.append(data_uri)

# Return both lists wrapped in a dictionary
return {"svg_list": svg_list, "b64_list": b64_list}
